    {"id": 2,  "title": "The Seven Husbands of Evelyn Hugo", "author": "Taylor Jenkins Reid", "year": 2017, "category": "romance",  "description": "Reclusive Hollywood icon Evelyn Hugo finally tells her life story to an unknown journalist — a sweeping saga of ambition, sacrifice, and the one true love she hid from the world for decades.", "image": "https://covers.openlibrary.org/b/id/10481893-L.jpg"},
    {"id": 3,  "title": "Outlander",                    "author": "Diana Gabaldon",          "year": 1991, "category": "romance",  "description": "A 1945 British nurse is transported through standing stones to 18th-century Scotland, where she falls for the fierce Highland warrior Jamie Fraser while torn between two centuries.", "image": "https://covers.openlibrary.org/b/id/8231856-L.jpg"},
