    {"id": 6,  "title": "People We Meet on Vacation",   "author": "Emily Henry",             "year": 2021, "category": "romance",  "description": "Alex and Poppy have been best friends for a decade, taking one vacation together every year. Then one disastrous trip ruins everything.", "image": "https://covers.openlibrary.org/b/id/10907612-L.jpg"},
