    {"id": 8,  "title": "It Ends with Us",              "author": "Colleen Hoover",          "year": 2016, "category": "romance",  "description": "Lily falls completely for charming neurosurgeon Ryle — but history begins repeating itself in ways she recognizes from her childhood.", "image": "https://covers.openlibrary.org/b/id/10226807-L.jpg"},
